function login() {
	   url = "https://api.uuxiaoshuo.vip/api/logins"
    cookie.removeCookie(source.key)
    cookie.removeCookie(url)
    res = source.getLoginInfoMap()
    use = res.get("帐号");
    pwd = java.md5Encode(res.get("密码"));
    body = {"username":use,"password":pwd}
    t = Math.floor(Date.now()/1e3)
    s = java.md5Encode(t+"1eb877de692dacb39cbce1ce0cd224fd").toLowerCase()
    h = {"timestamp":t,"sign":s}
    tb = java.ajax(url+","+JSON.stringify({
  "body": body,
  "method": "POST",
  "headers": java.log(JSON.stringify(h))
    	}))
     res = JSON.parse(tb)
     key = "9a1d65b4a693ad0e40e5b156df25e406"
     i = res.data.suffix
     iv = "9a61e6977b"+i
     d = res.data.data
     da = java.createSymmetricCrypto("AES/CBC/PKCS7Padding", key, iv).decryptStr(d)
     //java.log(da)
     tk=JSON.parse(da).token
    	source.putLoginHeader(tk)

}

