loginUrl:
function login() {}
function api() { 	java.startBrowserAwait(source.bookSourceUrl+'/',"接口文档");
    }
function vip() { 	java.startBrowserAwait(source.bookSourceUrl+'/coffee',"喝咖啡");
    }
function hqmy() { 	java.startBrowserAwait(source.bookSourceUrl+'/key',"获取密钥");
    }
var ms = source.getVariable();
function get(arg) {
	  var datadist = {
  "-1": "纯净阅读",
  "-2": "纯净漫画",
  "51": "多人发音",
  "1": "甜美少女",
  "2": "清亮青叔",
  "5": "开朗青年",
  "6": "温柔淑女",
  "4": "成熟大叔",
  "74": "大叔升级"
};
var tishi = '\n\n当前模式：'+datadist[arg]
    java.toast(tishi);
}
function set(mode,name) {
	   let toast = "\n\n已切换至：" + name+'\n\n切换后需要刷新详情页';
	   source.setVariable(mode);
 	   java.toast(toast);
    }
function zr() {
	   let toast ='\n\n真人语音无法手动切换\n\n前往搜索找包含主播的书籍进入即可';
	   java.toast(toast);
    }
function mh() {
	   let toast ='\n\n漫画无法手动切换\n\n前往搜索找包含主播的书籍进入即可';
	   java.toast(toast);
    }

function fq_login() { 	var cookie = java.getCookie("fanqienovel.com")
    java.log(cookie)
    if (cookie && cookie != "") {
        java.toast("请不要重复登录，请先退出登录！")
        return false
    }
    try {
        java.startBrowserAwait("https://fanqienovel.com/", "登录")
    } catch (e) {
        java.toast(e)
    }
    try {
        cookie.removeCookie("snssdk.com")
    } catch (e) {}
    var cookie = java.getCookie("fanqienovel.com")
    if (!cookie || cookie == "") {
        java.toast("登录失败！")
        return false
    }
    java.toast("登录成功！")
    return true
}


// 退出登录
function logout() {
    cookie.removeCookie("fanqienovel.com");
    cookie.removeCookie("snssdk.com");
    java.toast("退出登录成功");
}

