ruleToc.nextTocUrl:
@js:(function(result) {
    try {
        // 1. 解析页面源码（符合Legado Jsoup调用规范）
        var doc = org.jsoup.Jsoup.parse(result);
        // 2. 定位“下一页”按钮：匹配ul.ewave-page内、含“下一页”文本的a标签
        var nextLinkElem = doc.select("ul.ewave-page a:contains(下一页)").first();
        var nextUrl = "";

        if (nextLinkElem) {
            // 3. 提取下一页链接，处理空值（避免Legado因null报错）
            nextUrl = nextLinkElem.attr("href") || "";
            // 4. 匹配URL格式“/index.php/art/type/id/28/page/数字.html”，提取“page/”后的页码
            var pageMatch = nextUrl.match(/index\.php\/art\/type\/id\/\d+\/page\/(\d+)\.html/);

            if (pageMatch && pageMatch[1]) {
                // 5. 校验页码为纯数字并转换为数值类型
                var nextPage = /^\d+$/.test(pageMatch[1]) ? parseInt(pageMatch[1], 10) : 0;
                // 6. 核心控制：页码>10时返回空（Legado空值触发停止加载下一页）
                if (nextPage > 10) {
                    nextUrl = "";
                }
            } else {
                // URL格式不匹配（非目标分页链接），设为空
                nextUrl = "";
            }
        }

        // 7. 返回结果（单个URL/空值，符合Legado nextTocUrl格式要求）
        return nextUrl;
    } catch (e) {
        // 8. 异常兜底：避免脚本报错中断书源加载
        return "";
    }
})(result)

