ruleToc.nextTocUrl:
@js:(function(result) {
    try {
        // 1. 解析页面源码，遵循Legado Jsoup调用规范
        var doc = org.jsoup.Jsoup.parse(result);
        // 2. 定位当前页码：从ul.pagination内a.active标签提取（标识当前页）
        var currentPageElem = doc.select("ul.pagination a.active").first();
        var currentPage = 0;

        if (currentPageElem) {
            // 3. 提取并转换当前页码，容错非数字格式
            var currentPageText = currentPageElem.text().trim() || "0";
            currentPage = /^\d+$/.test(currentPageText) ? parseInt(currentPageText, 10) : 0;
        }

        // 4. 定位下一页链接：匹配ul.pagination内id为next-page的a标签
        var nextLinkElem = doc.select("ul.pagination a#next-page").first();
        var nextUrl = "";

        // 5. 按需求判断：页码≤10返回链接，否则返回空（空值触发Legado停止加载）
        if (nextLinkElem && currentPage <= 10) {
            nextUrl = nextLinkElem.attr("href").trim() || "";
        }

        // 6. 返回结果：符合规则返回链接，否则空值
        return nextUrl;
    } catch (e) {
        // 7. 异常兜底：避免报错中断加载，返回空值
        return "";
    }
})(result)

