@js:(function(result) {
    try {
        // 1. 解析页面源码（遵循Legado Jsoup调用规范）
        var doc = org.jsoup.Jsoup.parse(result);
        // 2. 定位当前页码：从.pagination内active类标签提取文本（如“1”）
        var currentPageElem = doc.select("div.pagination a.active").first();
        var currentPage = 0;

        if (currentPageElem) {
            // 3. 提取并转换当前页码（容错非数字格式）
            var currentPageText = currentPageElem.text().trim() || "0";
            currentPage = /^\d+$/.test(currentPageText) ? parseInt(currentPageText, 10) : 0;
        }

        // 4. 定位下一页按钮：匹配.pagination内title为“下一页”的链接
        var nextLinkElem = doc.select("div.pagination a[title='下一页']").first();
        var nextUrl = "";

        if (nextLinkElem && currentPage <= 10) {
            // 5. 页码≤10时提取下一页链接，否则返回空
            nextUrl = nextLinkElem.attr("href").trim() || "";
        }

        // 6. 返回结果：≤10返回链接，否则空值（Legado空值停止加载）
        return nextUrl;
    } catch (e) {
        // 7. 异常兜底：避免脚本报错导致加载中断
        return "";
    }
})(result)

